function GetImgCatalog(prop) { 
    if (prop.id <= 1 ) {
        return (
            <a href={prop.url} className="text-color-heavenly" target="_blank" rel="noreferrer"> 
                <div className="selector-ripples-auto selector selector-simple" style={{background: 'url(' + prop.img + ') center center'}}>
                    <div></div>
                </div> 
            </a>
        )    
    } else if (prop.id > 1 && prop.id <= 5 ) {
        return (
            <a href={prop.url} className="text-color-heavenly" target="_blank" rel="noreferrer"> 
                <div className="selector-ripples selector selector-simple" style={{background: 'url(' + prop.img + ') center center'}}>
                    <div></div>
                </div> 
            </a>
        )  
    } else {
        return (
            <a href={prop.url} className="text-color-heavenly" target="_blank" rel="noreferrer"> 
                <div className="selector selector-simple" style={{background: 'url(' + prop.img + ') center center'}}>
                    <div></div>
                </div> 
            </a>
        )  
    }
}

function GetImgSpiner(prop) { 
    return (
        <a href={prop.url} className="text-color-heavenly" target="_blank" rel="noreferrer"> 
            <img src= {prop.img} data-i = {prop.i} alt="" className="card__image"></img>
        </a>
    )
}

function GetTitle (props) { 
     return <h3 className="card__title">{props.title}</h3>
}

function GetUrlGithub (props) {
    return ( 
            <a className="card__url" href = {props.url} target="_blank" rel="noreferrer"> 
                <span style={{color: 'black'}}> GitHub: </span> {props.url}
            </a>
    )
}

function GetInfo (props) {
    return (
        <div>
            <p className="card__info">Сборка на {props.info} </p>
            <span className = "bottom">
                <GetUrelLogo url = {props.url}/>
            </span>
        </div>
     )
}

function GetUrelLogo (props) {
    return <img alt="Логотип программы " src={props.url} height="25" className = "bottom"/>
}




class Catalog extends React.Component {
    render() {
        let data = this.props.data;
        const rows = []; 
        let i = 0;
        data.forEach((data) => {
            rows.push(
                <article key = {data.id} className="card catalog__item" data-i = {i}>
                    <GetImgCatalog key = {data.urlSite + data.id} url = {data.urlSite} img = {data.img} id = {data.id}/>
                    <div className="card__description">
                        <GetTitle key = {data.title}  title = {data.title}/>
                        <GetUrlGithub key = {data.urlGithub} url = {data.urlGithub}/>
                        <GetInfo key = {data.info + i}  info = {data.info} url = {data.urlLogo} /> 
                    </div>

                </article>
            );
            i++;
        });
        return <React.Fragment> {rows} </React.Fragment>
    }
}

class CatalogForSpinner extends React.Component {
    render() {
        let data = this.props.data;
        const rows = []; 
        let i = 0;
        data.forEach((data) => {
            rows.push(
                <article key = {data.id}  >
                    <div className="scale">
                        <GetImgSpiner key = {data.urlSite + data.id} url = {data.urlSite} img = {data.img}/>
                    </div>
                    <div className="content">
                        <GetTitle key = {data.title}  title = {data.title}/>
                        <GetUrlGithub key = {data.urlGithub} url = {data.urlGithub}/>
                        <GetInfo key = {data.info + i}  info = {data.info} url = {data.urlLogo} /> 
                    </div>
                </article>
            );
            i++;
        });
        return <React.Fragment> {rows} </React.Fragment>
    }
}

