function ShowMode (props) {
    const isShowMode = props.isShowMode;
    if (isShowMode) {
        return <ShowGrid/>;
    }
    return <ShowSpinner/>;
}

class ShowGrid extends React.Component {
    constructor(props) {
        super(props)
        this.data = data;
    }

    ListSiteGulp() {
        let data1 = [];
        for (const item of this.data) {
            if (item.info === 'GulpJS') {
                data1.push(item);
            } 
        }
        return data1;
    }
    
    ListSiteReact() {
        let data2 = [];
        for (const item of this.data) {
            if (item.info === 'React') {
                data2.push(item);
            } 
        }
        return data2;
    }

    ListSitePhpMyAdmin() {
        let data3 = [];
        for (const item of this.data) {
            if (item.info === 'PhpMyAdmin') {
                data3.push(item);
            } 
        }
        return data3;
    }

    ListSiteCodeIgniter() {
        let data4 = [];
        for (const item of this.data) {
            if (item.info === 'CodeIgniter') {
                data4.push(item);
            } 
        }
        return data4;
    }

    render() {
        const dataGulp = this.ListSiteGulp();
        const dataReact = this.ListSiteReact();
        const dataPhp = this.ListSitePhpMyAdmin();
        // const dataCodeIgniter = this.ListSiteCodeIgniter();
        return (
            <>
                <main className="catalog page__catalog">
                    <Catalog key = {dataGulp.toString()} data = {dataGulp}/>
                    <Catalog key={dataReact.toString()} data = {dataReact}/>
                    <Catalog key={dataPhp.toString()} data = {dataPhp}/>
                </main>
            </>
        )
    }
}


class ShowSpinner extends React.Component {
    constructor(props) {
        super(props)
        this.data = data;
        this.state = {angle: 0};

        this.GallerySpinRight = this.clickRight.bind(this);
        this.GallerySpinLeft = this.clickLeft.bind(this);
    }

    ListSiteGulp() {
        let data1 = [];
        for (const item of this.data) {
            if (item.info === 'GulpJS') {
                data1.push(item);
            } 
        }
        return data1;
    }
    
    ListSiteReact() {
        let data2 = [];
        for (const item of this.data) {
            if (item.info === 'React') {
                data2.push(item);
            } 
        }
        return data2;
    }

    ListSitePhpMyAdmin() {
        let data3 = [];
        for (const item of this.data) {
            if (item.info === 'PhpMyAdmin') {
                data3.push(item);
            } 
        }
        return data3;
    }

    ListSiteCodeIgniter() {
        let data4 = [];
        for (const item of this.data) {
            if (item.info === 'CodeIgniter') {
                data4.push(item);
            } 
        }
        return data4;
    }

    clickRight() {
        const fun = () => {
            // let angle = 0;
            let spinner = document.querySelector('.spinner');
            let lenght = spinner.querySelectorAll('article').length;
            let angle = this.state.angle + 360/lenght;
            // console.log(angle);
            this.setState({
                angle: angle
            });
            spinner.setAttribute("style", "transform: rotateY("+ angle + "deg);"); // transform
        };
        fun();
    }
    clickLeft() {
        const fun = () => {
            // let angle = 0;
            let spinner = document.querySelector('.spinner');
            let lenght = spinner.querySelectorAll('article').length;
            let angle = this.state.angle - 360/lenght;

            this.setState({
                angle: angle
            });
            // console.log(angle);
            spinner.setAttribute("style", "transform: rotateY("+ angle + "deg);"); // transform
        }
        fun();
    }

    componentDidMount() {
        // console.log(this.state.angle);
    }

    render() {
        // console.log(this.state.angle);
        const dataGulp = this.ListSiteGulp();
        const dataReact = this.ListSiteReact();
        const dataPhp = this.ListSitePhpMyAdmin();
        // const dataCodeIgniter = this.ListSiteCodeIgniter();
        return (
            <>
                <div className="conva" >
                    <nav>
                        <button className="next-left btn-primary" onClick={this.GallerySpinRight}>&lt; </button>
                        <button className="next-right btn-primary" onClick={this.GallerySpinLeft}>&gt; </button>
                    </nav>
                    <div className="slider">
                        <div className="spinner">
                            <CatalogForSpinner key = {dataGulp.toString()} data = {dataGulp}/>
                            <CatalogForSpinner key = {dataReact.toString()} data = {dataReact}/>
                            <CatalogForSpinner key = {dataPhp.toString()} data = {dataPhp}/>
                        </div>
                    </div>
                </div>
            </>
        );
    }
}


function ButtonGrid(props) {
    return (
        <div className="btn btn-warning" onClick={props.onClick}>
            Сетка
        </div>
    );
}

function ButtonSnipper(props) {
    return (
        <div className="btn btn-warning" onClick={props.onClick}>
            Спиннер
        </div>
    );
}

export default class App extends React.Component {
    constructor(props) {
        super(props)
        this.data = data;

        this.gClick1 = this.click1.bind(this);
        this.gClick2 = this.click2.bind(this);
        this.state = {isShowMode: true};
    }

    click1() {
        window.location.reload();
        this.setState({isShowMode: true});
    }
    click2() {
        this.setState({isShowMode: false});
    }

    componentDidMount () {
        const script = document.createElement("script");
        script.src = "https://ajax.googleapis.com/ajax/libs/jquery/3.5.1/jquery.min.js";
        // script.async = true;
        script.async = false;
        document.body.appendChild(script);

        const script1 = document.createElement("script");
        script1.src = "./assets/js/jquery.ripples.js";
        // script1.async = true;
        script1.async = false;
        document.body.appendChild(script1);

        const script2 = document.createElement("script")
        script2.src = "./assets/js/jquery.ripples-min.js";
        // script2.async = true;
        script2.async = false;
        document.body.appendChild(script2);

        const script3 = document.createElement("script")
        script3.src = "./assets/js/script.js";
        // script3.async = true;
        script3.async = false;
        document.body.appendChild(script3);
    }

    render() {
        const isShowMode = this.state.isShowMode;
        let button;
        if (isShowMode) {
            // window.location.reload();
            button = <ButtonGrid onClick={this.gClick2} />;
            
        } else {
            button = <ButtonSnipper onClick={this.gClick1} />;
        }
        return (
            <>
                <header className="header">
                        <Header/>
                        {button}
                </header>
                <ShowMode isShowMode={isShowMode} />
                
            </>
        );
    }
}